import { createContext, useContext, useState, useEffect } from 'react'
import { useNavigate, useLocation } from 'react-router-dom'
import api, { getBaseURL } from '../utils/api'

const AuthContext = createContext(null)

export function AuthProvider({ children }) {
  const [user, setUser] = useState(null)
  const [loading, setLoading] = useState(true)
  const navigate = useNavigate()
  const location = useLocation()

  useEffect(() => {
    // Check for tokens in URL params (from Discord OAuth callback)
    const urlParams = new URLSearchParams(window.location.search)
    const accessToken = urlParams.get('access_token')
    const refreshToken = urlParams.get('refresh_token')

    if (accessToken && refreshToken) {
      // Store tokens
      localStorage.setItem('accessToken', accessToken)
      localStorage.setItem('refreshToken', refreshToken)

      // Clean up URL
      window.history.replaceState({}, document.title, location.pathname)

      // Fetch user info
      fetchUser()
    } else {
      // Check for existing token
      const token = localStorage.getItem('accessToken')
      if (token) {
        fetchUser()
      } else {
        setLoading(false)
      }
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [])

  const fetchUser = async () => {
    try {
      const userData = await api.get('/auth/me')
      setUser(userData.user)
      setLoading(false)
    } catch (error) {
      // Token invalid, clear storage
      localStorage.removeItem('accessToken')
      localStorage.removeItem('refreshToken')
      setUser(null)
      setLoading(false)
    }
  }

  const login = () => {
    // Redirect to Discord OAuth using the correct API base URL
    const apiBaseURL = getBaseURL()
    const discordUrl = `${apiBaseURL}/auth/discord?redirect_uri=` + encodeURIComponent(window.location.origin)
    console.log('[Auth] Redirecting to Discord OAuth:', discordUrl)
    window.location.href = discordUrl
  }

  const logout = async () => {
    try {
      await api.post('/auth/logout')
    } catch (error) {
      console.error('Logout error:', error)
    } finally {
      localStorage.removeItem('accessToken')
      localStorage.removeItem('refreshToken')
      setUser(null)
      navigate('/login')
    }
  }

  const value = {
    user,
    loading,
    login,
    logout,
    refreshUser: fetchUser,
  }

  return <AuthContext.Provider value={value}>{children}</AuthContext.Provider>
}

export function useAuth() {
  const context = useContext(AuthContext)
  if (!context) {
    throw new Error('useAuth must be used within an AuthProvider')
  }
  return context
}

